#include <vector>
#include <algorithm>
#include <omp.h>

void kernel_floyd_warshall(int n, std::vector<std::vector<int>>& path)
{
    // Flatten the 2‑D `path` into a 1‑D array for faster pointer math
    std::vector<int*> rows(n);
    for (int i = 0; i < n; ++i) rows[i] = path[i].data();

    // Main triple loop – parallelise the outer `i` loop
    for (int k = 0; k < n; ++k) {
        int *pk = rows[k];          // optimisation: keep a single row pointer
#pragma omp parallel for schedule(static)
        for (int i = 0; i < n; ++i) {
            int *pi = rows[i];
            int via = pi[k];        // pre‑load path[i][k] once per i
            for (int j = 0; j < n; ++j) {
                int cand = via + pk[j];
                if (cand < pi[j]) pi[j] = cand;
            }
        }
    }
}
