#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_1d(int tsteps,
                      int n,
                      std::vector<double>& A,
                      std::vector<double>& B) {
    const double alpha = 1.0 / 3.0;          // 0.33333
    const int stride = 1;                    // for clarity

    // Pointers for faster indexing
    double *restrict a = A.data();
    double *restrict b = B.data();

    for (int t = 0; t < tsteps; ++t) {
        /* 1st sweep: A -> B */
        #pragma omp parallel for schedule(static, stride)
        for (int i = 1; i < n - 1; ++i) {
            b[i] = alpha * (a[i-1] + a[i] + a[i+1]);
        }

        /* 2nd sweep: B -> A */
        #pragma omp parallel for schedule(static, stride)
        for (int i = 1; i < n - 1; ++i) {
            a[i] = alpha * (b[i-1] + b[i] + b[i+1]);
        }
    }
}
