#include <vector>
#include <omp.h>

void kernel_covariance(int m, int n,
                       std::vector<std::vector<double>>& data,
                       std::vector<std::vector<double>>& cov,
                       std::vector<double>& mean)
{
    /* ---------- 1. compute means  --------------------------------------*/
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double s = 0.0;
        for (int i = 0; i < n; ++i) s += data[i][j];
        mean[j] = s / n;
    }

    /* ---------- 2. center the data  -------------------------------------*/
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < m; ++j)
            data[i][j] -= mean[j];

    /* ---------- 3. covariance, upper triangle only ---------------------*/
    #pragma omp parallel for schedule(dynamic)
    for (int i = 0; i < m; ++i) {
        for (int j = i; j < m; ++j) {
            double s = 0.0;
            for (int k = 0; k < n; ++k)
                s += data[k][i] * data[k][j];
            s /= (n - 1.0);
            cov[i][j] = s;
            if (i != j) cov[j][i] = s;   // symmetry
        }
    }
}
