```cpp
#include <vector>
#include <cstring>
#include <algorithm>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_durbin(int n,
                   std::vector<double>& r,
                   std::vector<double>& y) {

    // Allocate temporary storage once
    double* z = static_cast<double*>(std::malloc(sizeof(double) * n));
    if (!z) return;                                 // safety

    y[0] = -r[0];
    double beta  = 1.0;
    double alpha = -r[0];

    for (int k = 1; k < n; ++k) {
        beta = (1.0 - alpha * alpha) * beta;

        // Compute sum = Σ_{i=0}^{k-1} r[k-i-1] * y[i]
        double sum = 0.0;
        const double* rptr = r.data();
        const double* yptr = y.data();
        for (int i = 0; i < k; ++i) {
            sum += rptr[k - i - 1] * yptr[i];
        }

        alpha = -(r[k] + sum) / beta;

        // Update temporary z and then copy back to y
        for (int i = 0; i < k; ++i) {
            z[i] = yptr[i] + alpha * yptr[k - i - 1];
        }
        std::memcpy(y.data(), z, sizeof(double) * k);

        y[k] = alpha;
    }

    std::free(z);
}
