/* Main computational kernel.
 * The whole function will be timed, including the call and return.
 * Exact behaviour is preserved. */
void kernel_syrk(int n, int m,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A)
{
    // Prepare row pointers for faster access
    std::vector<double*> Crow(n), Arow(n);
    for (int i = 0; i < n; ++i) {
        Crow[i] = C[i].data();
        Arow[i] = A[i].data();
    }

    // Parallelise outer i‑loop (lower triangle only)
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double* ci = Crow[i];
        double* ai = Arow[i];
        // First scale C[i][j] by beta for j <= i
        for (int j = 0; j <= i; ++j) ci[j] *= beta;

        // Accumulate alpha * A[i][k] * A[j][k]
        for (int k = 0; k < m; ++k) {
            const double aik = alpha * ai[k];
            for (int j = 0; j <= i; ++j)
                ci[j] += aik * Arow[j][k];
        }
    }
}
```
This replacement keeps the original algorithm and ordering, but:
* Uses raw pointers for row data to eliminate bounds checks.
* Pre‑computes `alpha * A[i][k]` to reduce multiplications.
* Parallelises the outer loop over `i` with OpenMP, exploiting the 8 available threads.
* Uses a static schedule, which is well‑suited for the regular workload.

