#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gesummv(int n,
                    double alpha,
                    double beta,
                    std::vector<std::vector<double>>& A,
                    std::vector<std::vector<double>>& B,
                    std::vector<double>& tmp,
                    std::vector<double>& x,
                    std::vector<double>& y)
{
    /* Use openmp parallel for with collapse if possible.  */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double tmp_i = 0.0;
        double y_i   = 0.0;
        const double* Arow = A[i].data();
        const double* Brow = B[i].data();
        const double* xx   = x.data();

        /* Unroll the inner loop for a small amount of work per iteration. */
        int j = 0;
        /* Handle 4 elements per loop to give the compiler a chance to fuse loads */
        for (; j <= n-4; j += 4) {
            tmp_i += Arow[j  ] * xx[j  ];
            tmp_i += Arow[j+1] * xx[j+1];
            tmp_i += Arow[j+2] * xx[j+2];
            tmp_i += Arow[j+3] * xx[j+3];

            y_i   += Brow[j  ] * xx[j  ];
            y_i   += Brow[j+1] * xx[j+1];
            y_i   += Brow[j+2] * xx[j+2];
            y_i   += Brow[j+3] * xx[j+3];
        }
        /* Tail */
        for (; j < n; ++j) {
            tmp_i += Arow[j] * xx[j];
            y_i   += Brow[j] * xx[j];
        }

        tmp[i] = tmp_i;
        y[i]   = alpha * tmp_i + beta * y_i;
    }
}
