#include <vector>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trisolv(int n,
                    std::vector<std::vector<double>>& L,
                    std::vector<double>& x,
                    std::vector<double>& b) {
    // Work with raw pointers for maximal speed.
    for (int i = 0; i < n; ++i) {
        const std::vector<double>* row = &L[i];
        const double* lrow = row->data();      // pointer to the i‑th row of L
        double vi = b[i];                      // start with the right‑hand‑side

        // Compute the dot‑product with all previous rows.
        for (int j = 0; j < i; ++j) {
            vi -= lrow[j] * x[j];
        }

        // Divide by the diagonal element.
        x[i] = vi / lrow[i];
    }
}
