/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_doitgen(int nr, int nq, int np,
                    std::vector<std::vector<std::vector<double>>>& A,
                    std::vector<std::vector<double>>& C4,
                    std::vector<double>& sum) {
    // Local pointer to contiguous C4 data for faster access
    double *c4 = &C4[0][0];
    // Allocate a reusable temporary for the row‑wise product
    std::vector<double> tmp(np);                 // will act as sum[]
    tmp.resize(np);

    #pragma omp parallel for collapse(2) schedule(static)
    for (int r = 0; r < nr; ++r) {
        for (int q = 0; q < nq; ++q) {
            double *a_row = &A[r][q][0];        // pointer to current row of A
            // compute a_row = a_row * C4 (row vector times matrix)
            for (int p = 0; p < np; ++p) {
                double acc = 0.0;
                for (int s = 0; s < np; ++s) {
                    acc += a_row[s] * c4[s * np + p];
                }
                tmp[p] = acc;
            }
            // write result back
            for (int p = 0; p < np; ++p) {
                a_row[p] = tmp[p];
            }
        }
    }
}
