/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trmm(int m, int n,
                 double alpha,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B) {

    // Flatten the 2‑D vectors into row‑major contiguous arrays
    // for faster cache‑friendly access
    std::vector<double> A_flat(m * m);
    std::vector<double> B_flat(m * n);

    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < m; ++j) {
            A_flat[i * m + j] = A[i][j];
        }
    }
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            B_flat[i * n + j] = B[i][j];
        }
    }

    /* Main loop.  The outer index i can be parallelised because
       each iteration writes only to a distinct row of B. */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        double *B_row = &B_flat[i * n];
        int i_offset = i * m;          // offset for accessing A[k][i]
        for (int j = 0; j < n; ++j) {
            double sum = B_row[j];
            for (int k = i + 1; k < m; ++k) {
                sum += A_flat[k * m + i] * B_flat[k * n + j];
            }
            B_row[j] = alpha * sum;
        }
    }

    // Copy results back into the original 2‑D vector structure
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            B[i][j] = B_flat[i * n + j];
        }
    }
}
