#include <vector>
#include <omp.h>

void kernel_gemm(int ni, int nj, int nk,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B,
                 std::vector<std::vector<double>>& C)
{
    // Parallelise the outermost loop over i.  Each thread works on a
    // different row of C and uses only local registers for the
    // computations, so no false sharing occurs.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        // Pointers to the current row of A, C and the rows of B used
        // during the accumulation.  For maximum temporal locality the
        // rows of B are accessed in the inner j‑loop.
        std::vector<double>&   rowA = A[i];
        std::vector<double>&   rowC = C[i];

        // Scale the row of C by beta once before the accumulation.
        for (int j = 0; j < nj; ++j) {
            rowC[j] *= beta;
        }

        // Standard inner–product accumulation:  C[i][j] += alpha*A[i][k]*B[k][j].
        // The j‑loop is SIMD auto‑vectorised by the compiler.
        for (int k = 0; k < nk; ++k) {
            double aik = alpha * rowA[k];          // reuse product for all j
            const std::vector<double>& rowB = B[k];
            for (int j = 0; j < nj; ++j) {
                rowC[j] += aik * rowB[j];
            }
        }
    }
}
