#include <cmath>
#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/* QR Decomposition with Modified Gram Schmidt:
   http://www.inf.ethz.ch/personal/gander/ */
void kernel_gramschmidt(int m, int n,
                        std::vector<std::vector<double>>& A,
                        std::vector<std::vector<double>>& R,
                        std::vector<std::vector<double>>& Q) {

    // Ensure that the inner vectors are contiguous for better cache behaviour
    // (they already are if the caller created them that way, but we keep the
    // interface unchanged).
    for (int k = 0; k < n; ++k) {
        // --- Step 1: norm of column k of A ---
        double nrm = 0.0;
        #pragma omp parallel for reduction(+:nrm) schedule(static)
        for (int i = 0; i < m; ++i) {
            double val = A[i][k];
            nrm += val * val;
        }
        double rk = std::sqrt(nrm);
        R[k][k] = rk;

        // --- Step 2: generate normalized column Q(:,k) ---
        #pragma omp parallel for schedule(static)
        for (int i = 0; i < m; ++i) {
            Q[i][k] = A[i][k] / rk;
        }

        // --- Step 3: compute R(k,j) and update remaining columns of A ---
        for (int j = k + 1; j < n; ++j) {
            double rij = 0.0;

            // dot(Q(:,k), A(:,j))
            #pragma omp parallel for reduction(+:rij) schedule(static)
            for (int i = 0; i < m; ++i) {
                rij += Q[i][k] * A[i][j];
            }
            R[k][j] = rij;

            // A(:,j) -= Q(:,k) * rij
            #pragma omp parallel for schedule(static)
            for (int i = 0; i < m; ++i) {
                A[i][j] -= Q[i][k] * rij;
            }
        }
    }
}
