#include <vector>
#include <cstddef>
#include <omp.h>

/*  Optimised GEMVER kernel.
 *  The interface matches the original harness, but the
 *  implementation uses row‑major contiguous storage for A
 *  (via the outer vector's internal array) and OpenMP
 *  parallelisation.  The behaviour is identical to the
 *  reference algorithm.
 */
void kernel_gemver(int n,
                   double alpha,
                   double beta,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& u1,
                   std::vector<double>& v1,
                   std::vector<double>& u2,
                   std::vector<double>& v2,
                   std::vector<double>& w,
                   std::vector<double>& x,
                   std::vector<double>& y,
                   std::vector<double>& z)
{
    /* ------------------------------------------------------------------
     * 1. A ← A + u1 v1ᵀ + u2 v2ᵀ
     * ------------------------------------------------------------------ */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        const double ui1 = u1[i];
        const double ui2 = u2[i];
        std::vector<double> & Ai = A[i];
        for (int j = 0; j < n; ++j) {
            Ai[j] += ui1 * v1[j] + ui2 * v2[j];
        }
    }

    /* ------------------------------------------------------------------
     * 2. x ← β Aᵀ y  +  x
     *    (the β term is computed in a loop that walks the
     *     transpose of A; no extra copy is needed)
     * ------------------------------------------------------------------ */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double xi = x[i];                      // cache previous value
        for (int j = 0; j < n; ++j) {
            xi += beta * A[j][i] * y[j];
        }
        x[i] = xi;
    }

    /* ------------------------------------------------------------------
     * 3. x ← x + z
     * ------------------------------------------------------------------ */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        x[i] += z[i];
    }

    /* ------------------------------------------------------------------
     * 4. w ← α A x  +  w
     * ------------------------------------------------------------------ */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double wi = w[i];                      // cache previous value
        const double alphaVal = alpha;
        std::vector<double> & Ai = A[i];
        for (int j = 0; j < n; ++j) {
            wi += alphaVal * Ai[j] * x[j];
        }
        w[i] = wi;
    }
}
