/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_atax(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& x,
                 std::vector<double>& y,
                 std::vector<double>& tmp) {
    /* Ensure tmp has the proper size. */
    if ((int)tmp.size() != m) tmp.resize(m);

    /* --- 1. Compute tmp[i] = sum_j A[i][j] * x[j]  --- */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        double acc = 0.0;
        const double* row = A[i].data();
        const double* xv   = x.data();
        for (int j = 0; j < n; ++j)
            acc += row[j] * xv[j];
        tmp[i] = acc;
    }

    /* --- 2. Compute y[j] = sum_i A[i][j] * tmp[i]  (transpose of A) --- */
#pragma omp parallel for schedule(static)
    for (int j = 0; j < n; ++j) {
        double sum = 0.0;
        for (int i = 0; i < m; ++i)
            sum += A[i][j] * tmp[i];
        y[j] = sum;
    }
}
