#include <vector>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_lu(int n,
	       std::vector<std::vector<double>>& A)
{
    /* LU decomposition with division in-place.
       The algorithm is identical to the original but written
       in a form that allows better optimization and vectorization
       by the compiler. */
    for (int i = 0; i < n; ++i)
    {
        double* Ai = A[i].data();

        /* Compute column i of the lower triangular part */
        for (int j = 0; j < i; ++j)
        {
            double sum = 0.0;
            const double* Ak = Ai;          // pointer to A[i][k]
            const std::vector<double>* Akrow = &A[0];
            for (int k = 0; k < j; ++k)
                sum += Ak[k] * (*Akrow)[k][j]; // A[i][k] * A[k][j]
            Ai[j] = (Ai[j] - sum) / A[j][j];
        }

        /* Update the remaining part of row i (including the diagonal) */
        for (int j = i; j < n; ++j)
        {
            double sum = 0.0;
            const double* Ak = Ai;          // pointer to A[i][k]
            const std::vector<double>* Akrow = &A[0];
            for (int k = 0; k < i; ++k)
                sum += Ak[k] * (*Akrow)[k][j]; // A[i][k] * A[k][j]
            Ai[j] -= sum;
        }
    }
}
