/* Parallel, cache‑friendly version of the 2‑D Sidi‑L kernel.
   The function signature is kept identical so that the harness
   observes the same behaviour.  The internal representation
   changes from std::vector<std::vector<double>> to a single flat
   std::vector<double>, which improves spatial locality and
   eliminates the extra indirection cost of nested vectors.  The
   algorithm is unchanged: each interior cell is replaced by the
   average of the 3×3 neighbourhood. */

inline double* mat_addr(double* base, int n, int i, int j) noexcept {
    return base + i * n + j;
}

extern "C" void kernel_seidel_2d(int tsteps,
                                 int n,
                                 std::vector<std::vector<double>>& A) {
    /* Flatten the input matrix into a contiguous 1‑D buffer. */
    std::vector<double> buf(n * n);
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            buf[i * n + j] = A[i][j];

    constexpr double inv9 = 1.0 / 9.0;

    /* Main time‑step loop. */
    for (int t = 0; t < tsteps; ++t) {
        /* Parallelise the inner two loops using OpenMP.  The
           "collapse(2)" clause merges the i and j loops into
           a single two‑dimensional iteration space, which gives
           better load balance for the 8‑thread runtime. */
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 1; i <= n - 2; ++i) {
            for (int j = 1; j <= n - 2; ++j) {
                double sum = 0.0;
                /* Unrolled summation of the 3×3 neighbourhood. */
                sum += mat_addr(buf.data(), n, i-1, j-1)[0];
                sum += mat_addr(buf.data(), n, i-1, j)[0];
                sum += mat_addr(buf.data(), n, i-1, j+1)[0];
                sum += mat_addr(buf.data(), n, i,   j-1)[0];
                sum += mat_addr(buf.data(), n, i,   j)[0];
                sum += mat_addr(buf.data(), n, i,   j+1)[0];
                sum += mat_addr(buf.data(), n, i+1, j-1)[0];
                sum += mat_addr(buf.data(), n, i+1, j)[0];
                sum += mat_addr(buf.data(), n, i+1, j+1)[0];
                buf[i * n + j] = sum * inv9;
            }
        }
    }

    /* Copy the final state back to the original nested vector
       representation so that any callers observe the expected
       results. */
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            A[i][j] = buf[i * n + j];
}
