/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_syr2k(int n, int m,
                  double alpha,
                  double beta,
                  std::vector<std::vector<double>>& C,
                  std::vector<std::vector<double>>& A,
                  std::vector<std::vector<double>>& B)
{
    // Extract raw pointers for faster indexing
    const double* const Aptr = &A[0][0];
    const double* const Bptr = &B[0][0];
    double*       const Cptr = &C[0][0];

    const std::size_t strideA = static_cast<std::size_t>(m);
    const std::size_t strideB = static_cast<std::size_t>(m);
    const std::size_t strideC = static_cast<std::size_t>(n);

    const double aAlpha = alpha;   // local copy for speed
    const double aBeta  = beta;    // local copy for speed

    /* Parallelise over the outermost loop (rows of C).
       Each iteration works on a distinct row of C, so there are
       no write conflicts.  The inner loops are cache‑friendly
       because we touch consecutive memory locations in C.
       The work is divided in a static schedule to minimise overhead. */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i)
    {
        // Pointer to the start of row i in C
        double* Crow = Cptr + static_cast<std::size_t>(i) * strideC;

        // 1) Scale the lower‑triangular part of the row by beta
        for (int j = 0; j <= i; ++j)
        {
            Crow[j] *= aBeta;
        }

        // 2) Accumulate the rank‑2 update
        //    C[i][j] += alpha * ( A[j][k] * B[i][k] + B[j][k] * A[i][k] )
        for (int k = 0; k < m; ++k)
        {
            // Pointers to the current column k in A and B
            const double* Acol = Aptr + static_cast<std::size_t>(k) * strideA;
            const double* Bcol = Bptr + static_cast<std::size_t>(k) * strideB;

            const double aik = Acol[static_cast<std::size_t>(i)]; // A[i][k]
            const double bik = Bcol[static_cast<std::size_t>(i)]; // B[i][k]

            for (int j = 0; j <= i; ++j)
            {
                // Access A[j][k] and B[j][k] via the column pointers
                const double ajk = Acol[static_cast<std::size_t>(j)];
                const double bjk = Bcol[static_cast<std::size_t>(j)];

                Crow[j] += aAlpha * (ajk * bik + bjk * aik);
            }
        }
    }
}
