    const double* __restrict p_ptr = p.data();
    const double* __restrict s_ptr = s.data();
    const double* __restrict q_ptr = q.data();

    // Temporary scratch for s updates to avoid atomic races
    // Allocate a per-thread buffer
    const int num_threads = omp_get_max_threads();
    std::vector<std::vector<double>> s_local(num_threads, std::vector<double>(m, 0.0));

    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        std::vector<double>& s_local_buf = s_local[tid];

        // Main work: compute q[i] and accumulate contributions to s[j]
        #pragma omp for schedule(static)
        for (int i = 0; i < n; ++i) {
            double ai_base = 0.0; // unused: placeholder
            double qi = 0.0;
            const double* a_row = A[i].data();

            for (int j = 0; j < m; ++j) {
                const double a_val = a_row[j];
                s_local_buf[j] += r_ptr[i] * a_val;
                qi += a_val + p_ptr[j];
            }
            q[i] = qi;
        }
