    double* ey_p = &ey[0][0];
    double* hz_p = &hz[0][0];

    const std::size_t ny_stride = static_cast<std::size_t>(ny);
    const std::size_t nx_stride = static_cast<std::size_t>(nx);

    // Main time‑stepping loop
