        #pragma omp parallel for schedule(static)
        for (int j = 0; j < ny; ++j) {
            ey_p[j] = _fict_[t];
        }

        // === Update eye (y‑derivative) for all interior i
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 1; i < nx; ++i) {
            for (int j = 0; j < ny; ++j) {
                ey_p[i * ny_stride + j] -= 0.5 * (hz_p[i * ny_stride + j]
                                                  - hz_p[(i - 1) * ny_stride + j]);
