        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 0; i < nx; ++i) {
            for (int j = 1; j < ny; ++j) {
                ex_p[i * ny_stride + j] -= 0.5 * (hz_p[i * ny_stride + j]
                                                 - hz_p[i * ny_stride + (j - 1)]);
            }
        }

        // === Update hz (cross‑field coupling) for all interior points
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 0; i < nx - 1; ++i) {
            for (int j = 0; j < ny - 1; ++j) {
                const std::size_t idx   = i * ny_stride + j;
                const std::size_t idx_e = i * ny_stride + (j + 1);
