/* Main computational kernel.  The whole function will be timed,
   including the call and return. */
void kernel_cholesky(int n,
                     std::vector<std::vector<double>>& A)
{
    /* Flatten the 2‑D vector into a 1‑D array for better cache behaviour. */
    std::vector<double> flat(n * n);
    double* flat_ptr = flat.data();
    for (int i = 0; i < n; ++i) {
        std::memcpy(flat_ptr + i * n, A[i].data(), n * sizeof(double));
    }

    /* Core Cholesky factorisation.  `i` is the serial loop – we cannot
       parallelise it because each row depends on all previous rows. */
    for (int i = 0; i < n; ++i) {
        /* --- Off‑diagonal elements A[i][j] with j < i --- */
        for (int j = 0; j < i; ++j) {
            double sum = 0.0;
#pragma omp simd reduction(+:sum)
            for (int k = 0; k < j; ++k) {
                sum += flat[i * n + k] * flat[j * n + k];
            }
            flat[i * n + j] = (flat[i * n + j] - sum) / flat[j * n + j];
        }

        /* --- Diagonal element A[i][i] --- */
        double sum = 0.0;
#pragma omp simd reduction(+:sum)
        for (int k = 0; k < i; ++k) {
            double a = flat[i * n + k];
            sum += a * a;
        }
        flat[i * n + i] = std::sqrt(flat[i * n + i] - sum);
    }

    /* Copy the result back into the 2‑D vector. */
    for (int i = 0; i < n; ++i) {
        std::memcpy(A[i].data(), flat_ptr + i * n, n * sizeof(double));
    }
}
