/* Optimised Nussinov kernel.
   The signature must stay unchanged. */
void kernel_nussinov(int n, std::vector<int>& seq,
                     std::vector<std::vector<int>>& table)
{
    // Inline match function (matches A-C or U-G, i.e. 0+3 or 1+2)
    constexpr auto match = [](int a, int b) noexcept -> int {
        return (a + b == 3) ? 1 : 0;
    };

    // Raw pointers to the table data for faster accesses
    std::vector<int*> row_ptrs(n);
    for (int i = 0; i < n; ++i) row_ptrs[i] = table[i].data();

    // Main DP – processed diagonally anti‑wards.
    // Dependence order requires that i is processed from n‑1 downto 0,
    // and j from i+1 to n‑1.
    for (int i = n - 1; i >= 0; --i) {
        int* row_i   = row_ptrs[i];
        int* row_ip1 = (i + 1 < n) ? row_ptrs[i + 1] : nullptr;

        for (int j = i + 1; j < n; ++j) {
            int best = 0;
            int* row_jm1 = row_ptrs[j - 1];

            // Copy of existing value (table[i][j]) is zero‑initialised.
            // The initial value could be read from row_i[j] but it is zero.

            // 1) Skip j
            if (row_jm1) {
                int v = row_jm1[j];
                if (v > best) best = v;
            }
            // 2) Skip i
            if (row_ip1) {
                int v = row_ip1[j];
                if (v > best) best = v;
            }
            // 3) Pair (i,j)
            int vpair = 0;
            if (row_ip1) {
                vpair = row_ip1[j - 1];
                if (i < j - 1) vpair += match(seq[i], seq[j]);
            }
            if (vpair > best) best = vpair;
            // 4) Split at k
            int* row_ik = row_i;
            for (int k = i + 1; k < j; ++k) {
                int val = row_ik[k] + row_ptrs[k + 1][j];
                if (val > best) best = val;
            }

            row_i[j] = best;
        }
    }
}
