void kernel_correlation(int m, int n,
                        std::vector<std::vector<double>>& data,
                        std::vector<std::vector<double>>& corr,
                        std::vector<double>& mean,
                        std::vector<double>& stddev)
{
    // Flatten the 2‑D data for better cache locality
    std::vector<double> flat(m * n);
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < m; ++j)
            flat[i * m + j] = data[i][j];

    const double eps = 0.1;
    const double inv_n = 1.0 / n;
    const double sqrt_n = std::sqrt(n);

    /* ---- 1. Mean and stddev (serial but trivial) ---- */
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i)
            sum += flat[i * m + j];
        mean[j] = sum * inv_n;
    }

    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) {
            double x = flat[i * m + j] - mean[j];
            sum += x * x;
        }
        double var = sum * inv_n;
        stddev[j] = std::sqrt(var);
        if (stddev[j] <= eps) stddev[j] = 1.0;
    }

    /* ---- 2. Normalise data (in‑place with flat array) ---- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            double v = flat[i * m + j] - mean[j];
            v /= sqrt_n * stddev[j];
            flat[i * m + j] = v;
        }
    }

    /* ---- 3. Correlation matrix  (data^T * data)  ---- */
    // We compute only upper triangle and mirror it.
    // Blocked loop for better cache usage.
    const int B = 64; // block size tuned for L1 cache
    for (int ii = 0; ii < m; ii += B) {
        int i_end = std::min(ii + B, m);
        for (int jj = ii; jj < m; jj += B) {
            int j_end = std::min(jj + B, m);
            for (int i = ii; i < i_end; ++i) {
                for (int j = std::max(jj, i + 1); j < j_end; ++j) {
                    double acc = 0.0;
                    for (int k = 0; k < n; ++k)
                        acc += flat[k * m + i] * flat[k * m + j];
                    corr[i][j] = acc;
                    corr[j][i] = acc; // symmetry
                }
                if (i >= jj && i < j_end) {
                    corr[i][i] = 1.0;               // diagonal
                }
            }
        }
    }

    /* Fix remaining diagonal elements if any */
    for (int i = 0; i < m; ++i)
        corr[i][i] = 1.0;
}
