/* Helper to flatten a 2‑D vector of doubles into a single contiguous array
   using row-major layout. */
inline void flatten(const std::vector<std::vector<double>>& src,
                    double* dst, std::size_t n) {
    for (std::size_t i = 0; i < n; ++i)
        std::memcpy(dst + i * n, src[i].data(), n * sizeof(double));
}

/* Helper to copy a contiguous 2‑D array back into a vector<vector<double>> */
inline void unflatten(const double* src,
                      std::vector<std::vector<double>>& dst,
                      std::size_t n) {
    for (std::size_t i = 0; i < n; ++i)
        std::memcpy(dst[i].data(), src + i * n, n * sizeof(double));
}

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_ludcmp(int n,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& b,
                   std::vector<double>& x,
                   std::vector<double>& y) {
    /* Allocate a contiguous buffer for the matrix. */
    std::vector<double> mat(n * n);
    flatten(A, mat.data(), static_cast<std::size_t>(n));

    const std::size_t block = 32;   /* block size for cache friendliness */

    /* ------------------------------------------------------------
       LU factorisation :   L · U = A
       ------------------------------------------------------------ */
    for (int i = 0; i < n; ++i) {
        /* --- Lower triangle (strictly below the diagonal) --- */
        for (int j = 0; j < i; ++j) {
            double w = mat[i * n + j];

            /* Σ A[i][k] · A[k][j]  with k < j */
            #pragma omp simd reduction(-:w)
            for (int k = 0; k < j; ++k)
                w -= mat[i * n + k] * mat[k * n + j];

            mat[i * n + j] = w / mat[j * n + j];
        }

        /* --- Upper triangle (including diagonal) --- */
        for (int j = i; j < n; ++j) {
            double w = mat[i * n + j];

            /* Σ A[i][k] · A[k][j]  with k < i */
            #pragma omp simd reduction(-:w)
            for (int k = 0; k < i; ++k)
                w -= mat[i * n + k] * mat[k * n + j];

            mat[i * n + j] = w;
        }
    }

    /* ------------------------------------------------------------
       Forward substitution :   L · y = b
       ------------------------------------------------------------ */
    for (int i = 0; i < n; ++i) {
        double w = b[i];

        #pragma omp simd reduction(-:w)
        for (int j = 0; j < i; ++j)
            w -= mat[i * n + j] * y[j];

        y[i] = w;
    }

    /* ------------------------------------------------------------
       Back substitution :    U · x = y
       ------------------------------------------------------------ */
    for (int i = n - 1; i >= 0; --i) {
        double w = y[i];

        #pragma omp simd reduction(-:w)
        for (int j = i + 1; j < n; ++j)
            w -= mat[i * n + j] * x[j];

        x[i] = w / mat[i * n + i];
    }

    /* Copy the result back into the original matrix structure */
    unflatten(mat.data(), A, static_cast<std::size_t>(n));
}
