        std::vector<std::vector<double>>& C,
        std::vector<std::vector<double>>& D,
        std::vector<std::vector<double>>& G)
{
    /* convert the 2‑D std::vector layouts into flat pointers for
       efficient pointer arithmetic (the same layout as in the
       original code: row major). */
    std::vector<double> e_flat(ni * nj);
    std::vector<double> f_flat(nj * nl);
    std::vector<double> g_flat(ni * nl);

    /* pre‑flatten input matrices */
    std::vector<double> a_flat(ni * nk);
    std::vector<double> b_flat(nk * nj);
    std::vector<double> c_flat(nj * nm);
    std::vector<double> d_flat(nm * nl);

    for (int i = 0; i < ni; ++i)
        for (int k = 0; k < nk; ++k)
            a_flat[i * nk + k] = A[i][k];

    for (int k = 0; k < nk; ++k)
        for (int j = 0; j < nj; ++j)
            b_flat[k * nj + j] = B[k][j];

    for (int i = 0; i < nj; ++i)
        for (int k = 0; k < nm; ++k)
            c_flat[i * nm + k] = C[i][k];

    for (int k = 0; k < nm; ++k)
        for (int j = 0; j < nl; ++j)
            d_flat[k * nl + j] = D[k][j];

    /* 1st GEMM:  E = A * B  (ni x nj) */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < ni; ++i) {
        for (int j = 0; j < nj; ++j) {
            double sum = 0.0;
            int a_idx = i * nk;
            int b_idx = j;
            for (int k = 0; k < nk; ++k)
                sum += a_flat[a_idx + k] * b_flat[b_idx + k * nj];
            e_flat[i * nj + j] = sum;
        }
    }

    /* 2nd GEMM:  F = C * D  (nj x nl) */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < nj; ++i) {
        for (int j = 0; j < nl; ++j) {
            double sum = 0.0;
            int c_idx = i * nm;
            int d_idx = j;
            for (int k = 0; k < nm; ++k)
                sum += c_flat[c_idx + k] * d_flat[d_idx + k * nl];
            f_flat[i * nl + j] = sum;
        }
    }

    /* 3rd GEMM:  G = E * F  (ni x nl) */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < ni; ++i) {
        for (int j = 0; j < nl; ++j) {
            double sum = 0.0;
            int e_idx = i * nj;
            int f_idx = j;
            for (int k = 0; k < nj; ++k)
                sum += e_flat[e_idx + k] * f_flat[f_idx + k * nl];
            g_flat[i * nl + j] = sum;
        }
    }

    /* copy results back to the original 2‑D vectors */
    for (int i = 0; i < ni; ++i)
        for (int j = 0; j < nj; ++j)
            E[i][j] = e_flat[i * nj + j];

    for (int i = 0; i < nj; ++i)
        for (int j = 0; j < nl; ++j)
            F[i][j] = f_flat[i * nl + j];

    for (int i = 0; i < ni; ++i)
        for (int j = 0; j < nl; ++j)
            G[i][j] = g_flat[i * nl + j];
}
