#include <vector>
#include <cstddef>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_heat_3d(int tsteps,
                    int n,
                    std::vector<std::vector<std::vector<double>>>& A,
                    std::vector<std::vector<std::vector<double>>>& B)
{
    constexpr double coeff = 0.125;

    // For better locality we keep a pointer to the 2‑D slices of A and B.
    // We also keep a row pointer while iterating over j so that we only
    // perform a single dereference for each element access.
    for (int t = 1; t <= tsteps; ++t)
    {
        /* Write B from A */
        #pragma omp parallel for collapse(3) schedule(static)
        for (int i = 1; i < n - 1; ++i)
        {
            for (int j = 1; j < n - 1; ++j)
            {
                const std::vector<double>& aiplus = A[i + 1][j];
                const std::vector<double>& aiminus = A[i - 1][j];
                const std::vector<double>& aij = A[i][j];
                const std::vector<double>& aiplus_jplus = A[i + 1][j + 1];
                const std::vector<double>& aiminus_jplus = A[i - 1][j + 1];
                const std::vector<double>& aij_jplus = A[i][j + 1];
                const std::vector<double>& aiplus_jminus = A[i + 1][j - 1];
                const std::vector<double>& aiminus_jminus = A[i - 1][j - 1];
                const std::vector<double>& aij_jminus = A[i][j - 1];

                std::vector<double>& biplus = B[i + 1][j];
                std::vector<double>& biminus = B[i - 1][j];
                std::vector<double>& bij = B[i][j];

                for (int k = 1; k < n - 1; ++k)
                {
                    // compute x‑, y‑, and z‑differences for A
                    double ax = aiplus[k] + aiminus[k] - 2.0 * aij[k];
                    double ay = aij_jplus[k] + aij_jminus[k] - 2.0 * aij[k];
                    double az = aiplus[k + 1] + aiplus[k - 1] - 2.0 * aij[k];
                    B[i][j][k] = ax * coeff + ay * coeff + az * coeff + aij[k];
                }
            }
        }

        /* Write A from B (swap roles) */
        #pragma omp parallel for collapse(3) schedule(static)
        for (int i = 1; i < n - 1; ++i)
        {
            for (int j = 1; j < n - 1; ++j)
            {
                const std::vector<double>& biplus = B[i + 1][j];
                const std::vector<double>& biminus = B[i - 1][j];
                const std::vector<double>& bij = B[i][j];
                const std::vector<double>& biplus_jplus = B[i + 1][j + 1];
                const std::vector<double>& biminus_jplus = B[i - 1][j + 1];
                const std::vector<double>& bij_jplus = B[i][j + 1];
                const std::vector<double>& biplus_jminus = B[i + 1][j - 1];
                const std::vector<double>& biminus_jminus = B[i - 1][j - 1];
                const std::vector<double>& bij_jminus = B[i][j - 1];

                std::vector<double>& aiplus = A[i + 1][j];
                std::vector<double>& aiminus = A[i - 1][j];
                std::vector<double>& aij = A[i][j];

                for (int k = 1; k < n - 1; ++k)
                {
                    double bx = biplus[k] + biminus[k] - 2.0 * bij[k];
                    double by = bij_jplus[k] + bij_jminus[k] - 2.0 * bij[k];
                    double bz = biplus[k + 1] + biplus[k - 1] - 2.0 * bij[k];
                    A[i][j][k] = bx * coeff + by * coeff + bz * coeff + bij[k];
                }
            }
        }
    }
}
