#include <vector>
#include <omp.h>

/* Optimised kernel for ADI with 8 threads, gcc -O2 -fopenmp */
void kernel_adi(int tsteps, int n,
	        std::vector<std::vector<double>>& u,
	        std::vector<std::vector<double>>& v,
	        std::vector<std::vector<double>>& p,
	        std::vector<std::vector<double>>& q) {
    /* Pre‑compute constants */
    const double DX  = 1.0 / n;
    const double DY  = 1.0 / n;
    const double DT  = 1.0 / tsteps;
    const double B1  = 2.0;
    const double B2  = 1.0;
    const double mul1 = B1 * DT / (DX * DX);
    const double mul2 = B2 * DT / (DY * DY);
    const double a  = -mul1 / 2.0;
    const double b  = 1.0 + mul1;
    const double c  = a;
    const double d  = -mul2 / 2.0;
    const double e  = 1.0 + mul2;
    const double f  = d;

    /* Flatten access to2D vectors for cache friendliness */
    double* udata = &u[0][0];
    double* vdata = &v[0][0];
    double* pdata = &p[0][0];
    double* qdata = &q[0][0];

    const int stride = n;          // row stride
    const int lastInner = n - 2;   // last inner index
    const int firstInner = 1;      // first inner index

    for (int t = 1; t <= tsteps; ++t) {
        /* ---------- First pass : update v ---------- */
        #pragma omp parallel for schedule(static)
        for (int i = firstInner; i < lastInner; ++i) {
            int col = i * stride;                    // base index for column i

            vdata[col + 0] = 1.0;
            pdata[col + 0] = 0.0;
            qdata[col + 0] = vdata[col + 0];

            /* Forward sweep over j */
            for (int j = 1; j < lastInner; ++j) {
                int idx  = col + j;
                int idxm = col + j - 1;              // v[j-1][i]
                int uindL = (j-1) * stride + (i-1);  // u[j-1][i-1]
                int uindC = (j-1) * stride +  i;     // u[j-1][i]
                int uindR = (j-1) * stride + (i+1);  // u[j-1][i+1]

                double denom = a * pdata[idxm] + b;
                double inv    = -c / denom;
                pdata[idx]    = inv;

                double term = (-d * udata[uindL] + (1.0 + 2.0 * d) * udata[uindC]
                              - f * udata[uindR] - a * qdata[idxm]) / denom;
                qdata[idx] = term;
            }

            vdata[col + lastInner] = 1.0;

            /* Backward sweep over j */
            for (int j = lastInner - 1; j >= firstInner; --j) {
                int idx     = col + j;
                int idxp    = col + j + 1;
                vdata[idx] = pdata[idx] * vdata[idxp] + qdata[idx];
            }
        }

        /* ---------- Second pass : update u ---------- */
        #pragma omp parallel for schedule(static)
        for (int i = firstInner; i < lastInner; ++i) {
            int row = i * stride;                    // base index for row i

            udata[row + 0] = 1.0;
            pdata[row + 0] = 0.0;
            qdata[row + 0] = udata[row + 0];

            /* Forward sweep over j */
            for (int j = 1; j < lastInner; ++j) {
                int idx  = row + j;
                int idxm = row + j - 1;                // u[i][j-1]
                int vendL = (i-1) * stride + j;        // v[i-1][j]
                int vendC = (i  ) * stride + j;        // v[i][j]
                int vendR = (i+1) * stride + j;        // v[i+1][j]

                double denom = d * pdata[idxm] + e;
                double inv    = -f / denom;
                pdata[idx]    = inv;

                double term = (-a * vdata[vendL] + (1.0 + 2.0 * a) * vdata[vendC]
                              - c * vdata[vendR] - d * qdata[idxm]) / denom;
                qdata[idx] = term;
            }

            udata[row + lastInner] = 1.0;

            /* Backward sweep over j */
            for (int j = lastInner - 1; j >= firstInner; --j) {
                int idx  = row + j;
                int idxp = row + j + 1;
                udata[idx] = pdata[idx] * udata[idxp] + qdata[idx];
            }
        }
    }
}
