```cpp
#include <cmath>
#include <vector>
#include <omp.h>

/* Optimised Deriche kernel – identical semantics to the original code */

/* Note: the memory layout is unchanged – 2‑D std::vector of rows.
   All indexing is done with pointers for speed. */
void kernel_deriche(int w, int h, double alpha,
                    std::vector<std::vector<float>>& imgIn,
                    std::vector<std::vector<float>>& imgOut,
                    std::vector<std::vector<float>>& y1,
                    std::vector<std::vector<float>>& y2)
{
    /* ----------- pre‑compute constants ---------------------------------- */
    const float exp_a   = std::exp(-alpha);
    const float exp_2a  = exp_a * exp_a;
    const float denom   = 1.0f + 2.0f * alpha * exp_a - exp_2a;
    const float k       = 1.0f - exp_a * (1.0f - exp_a) / denom;
    const float a_common = k * exp_a;

    const float a1 = k, a5 = k;
    const float a2 = a6 = a_common * (alpha - 1.0f);
    const float a3 = a7 = a_common * (alpha + 1.0f);
    const float a4 = a8 = -k * exp_2a;
    const float b1 = std::pow(2.0f, -static_cast<float>(alpha));
    const float b2 = -exp_2a;
    const float c1 = 1.0f, c2 = 1.0f;

    /* ----------- temporary row pointers for cache locality ------------- */
    float *pIn[8], *pOut[8], *pY1[8], *pY2[8];
    for (int i = 0; i < w; ++i) {
        pIn[i]  = const_cast<float*>(imgIn[i].data());
        pOut[i] = imgOut[i].data();
        pY1[i]  = y1[i].data();
        pY2[i]  = y2[i].data();
    }

    /* ----- 1st pass: forward along rows --------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i)
    {
        const float *in  = pIn[i];
        float  * y1row = pY1[i];

        float ym1 = 0.0f, ym2 = 0.0f;
        float xm1 = 0.0f;

        for (int j = 0; j < h; ++j)
        {
            float val = a1 * in[j] + a2 * xm1 + b1 * ym1 + b2 * ym2;
            y1row[j] = val;
            xm1 = in[j];
            ym2 = ym1;
            ym1 = val;
        }
    }

    /* ----- 2nd pass: backward along rows -------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i)
    {
        const float *in  = pIn[i];
        float  * y2row = pY2[i];

        float yp1 = 0.0f, yp2 = 0.0f;
        float xp1 = 0.0f, xp2 = 0.0f;

        for (int j = h - 1; j >= 0; --j)
        {
            float val = a3 * xp1 + a4 * xp2 + b1 * yp1 + b2 * yp2;
            y2row[j] = val;
            xp2 = xp1;
            xp1 = in[j];
            yp2 = yp1;
            yp1 = val;
        }
    }

    /* ----- 3rd pass: combine row results -------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i)
    {
        float* out  = pOut[i];
        const float* y1row = pY1[i];
        const float* y2row = pY2[i];
        for (int j = 0; j < h; ++j)
            out[j] = c1 * (y1row[j] + y2row[j]);
    }

    /* ----- 4th pass: forward along columns ------------------------------ */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j)
    {
        float ym1 = 0.0f, ym2 = 0.0f;
        float tm1 = 0.0f;

        for (int i = 0; i < w; ++i)
        {
            float val = a5 * pOut[i][j] + a6 * tm1 + b1 * ym1 + b2 * ym2;
            pY1[i][j] = val;
            tm1 = pOut[i][j];
            ym2 = ym1;
            ym1 = val;
        }
    }

    /* ----- 5th pass: backward along columns ------------------------------ */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j)
    {
        float yp1 = 0.0f, yp2 = 0.0f;
        float tp1 = 0.0f, tp2 = 0.0f;

        for (int i = w - 1; i >= 0; --i)
        {
            float val = a7 * tp1 + a8 * tp2 + b1 * yp1 + b2 * yp2;
            pY2[i][j] = val;
            tp2 = tp1;
            tp1 = pOut[i][j];
            yp2 = yp1;
            yp1 = val;
        }
    }

    /* ----- 6th pass: final combine -------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i)
    {
        float* out  = pOut[i];
        const float* y1row = pY1[i];
        const float* y2row = pY2[i];
        for (int j = 0; j < h; ++j)
            out[j] = c2 * (y1row[j] + y2row[j]);
    }
}
